import type ParquetLayer from "../../layers/ParquetLayer.js";
import type FeatureLikeLayerView from "./FeatureLikeLayerView.js";

/**
 * Represents the [LayerView](https://developers.arcgis.com/javascript/latest/references/core/views/layers/LayerView/) of a [ParquetLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/ParquetLayer/)
 * after it has been added to a [Map](https://developers.arcgis.com/javascript/latest/references/core/Map/).
 *
 * The ParquetLayerView is responsible for rendering a [ParquetLayer's](https://developers.arcgis.com/javascript/latest/references/core/layers/ParquetLayer/)
 * features as [graphics](https://developers.arcgis.com/javascript/latest/references/core/Graphic/) in the [View](https://developers.arcgis.com/javascript/latest/references/core/views/View/).
 *
 * @since 4.33
 * @see [ParquetLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/ParquetLayer/)
 */
export default abstract class ParquetLayerView extends FeatureLikeLayerView {
  /** The layer being viewed. */
  get layer(): ParquetLayer;
}